mapper.update:
UPDATE flower_redemption
status = #{status}, confirm_time = #{confirmTime}, confirm_by = #{confirmBy}, remark = #{remark},
WHERE id = #{id}

mapper.select:
SELECT fr.* FROM flower_redemption fr
INNER JOIN user u ON u.id = fr.student_id
WHERE u.parent_id = #{parentId}
AND fr.status = #{status}
ORDER BY fr.redeem_time DESC

SELECT COALESCE(SUM(qty), 0) FROM flower_redemption
WHERE student_id = #{studentId}
  AND item_id    = #{itemId}
  AND redeem_date = #{today}
  AND status != 2
